                @click="setUpProfile()"
                class="text-xs md:text-base md:ml-auto text-blue font-bold px-4 py-2 rounded-full border border-blue mb-2 hover:bg-lightblue"
              >
                Set up profile
              </button>
              <button
                v-if="
                  profile.avatar !== null &&
                  profile.avatar !== '/default_profile.png'
                "
                @click="editProfile()"
                class="text-xs md:text-base md:ml-auto text-blue font-bold px-4 py-2 rounded-full border border-blue mb-2 hover:bg-lightblue"
              >
                Edit profile
              </button>
            </div>

            <div v-if="!noUser && !isSelf && !loading" class="relative">
              <button
                @click.stop="profileMenuOpen = !profileMenuOpen"
                class="text-xs md:text-base md:ml-auto mr-1 md:mr-3 text-blue font-bold px-3 py-1 md:px-3 md:py-2 rounded-full border border-blue mb-2 hover:bg-lightblue"
                :aria-expanded="profileMenuOpen"
                aria-label="More options"
              >
                <i class="fas fa-ellipsis-h"></i>
              </button>
              <div v-if="profileMenuOpen" class="absolute right-0 top-10 mt-1 w-48 bg-white dark:bg-darktheme-card mastodon:bg-mastodon-card rounded-md shadow-lg py-1 z-10">
                <button type="button" @click="toggleMuteFromProfile" class="block w-full text-left px-4 py-2 text-sm hover:bg-gray-100 flat-btn">{{ isMuted ? `Unmute @${profile.id}` : `Mute @${profile.id}` }}</button>
                <button
                  type="button"
                  @click="askBlockToggle"
                  class="block w-full text-left px-4 py-2 text-sm hover:bg-gray-100 flat-btn"
                  :class="isBlocked ? 'text-blue' : 'text-red-600'"
                >{{ isBlocked ? `Unblock @${profile.id}` : `Block @${profile.id}` }}</button>
                <button
                  type="button"
                  @click="openReport"
                  class="block w-full text-left px-4 py-2 text-sm text-red-600 hover:bg-gray-100 flat-btn"
                >Report @{{ profile.id }}</button>
              </div>
              <ReportDialog
                :show="showReportDialog"
                :title="`Report @${profile.id}`"
                @submit="submitReport"
                @cancel="showReportDialog = false"
              />
              <button
                v-if="isFollower()"
                @click="sendMessage()"
                class="text-xs md:text-base md:ml-auto mr-1 md:mr-3 text-blue font-bold px-3 py-1 md:px-3 md:py-2 rounded-full border border-blue mb-2 hover:bg-lightblue"
                aria-label="Send message"
              >
                <i class="fas fa-envelope" aria-hidden="true"></i>
              </button>
              <button
                v-if="!isFollowing()"
                @click="follow()"
                class="text-xs md:text-base md:ml-auto text-blue font-bold px-2 py-1 md:px-4 md:py-2 rounded-full border border-blue mb-2 hover:bg-lightblue w-24 md:w-28"
              >
                Follow
              </button>
              <button
                v-if="isFollowing()"
                @mouseover="followingLabel = 'Unfollow'"
                @mouseleave="followingLabel = 'Following'"
                @click="unfollow()"
                class="text-xs md:text-base md:ml-auto mr-1 md:mr-3 text-white bg-blue font-bold px-3 py-1 md:px-3 md:py-2 rounded-full border mb-2 hover:bg-red-700 w-22 md:w-28"
              >
                {{ followingLabel }}
              </button>
            </div>
          </div>
          <div v-if="!noUser && !loading" class="px-3">
            <p class="font-bold text-xl">{{ profile.username || '...' }}</p>
            <p class="text-dark">
              @{{ profile.id || '' }}
              <span
                  v-if="profile.isOffline"
                  class="text-sm font-medium bg-red-900 py-1 px-1 mx-2 rounded text-white align-middle"
              >Offline</span>
              <span
                  v-if="isBusiness"
                  class="text-sm font-medium bg-blue py-1 px-1 mx-2 rounded text-white align-middle"
              >Business</span>
              <span
                v-if="isFollower() && !isSelf"
                class="text-sm font-medium bg-gray-100 py-1 px-1 mx-2 rounded text-gray-500 align-middle"
              >Follows you</span>
            </p>
            <p :key="profile.bio || ''" class="my-2" v-linkify>{{ profile.bio || '' }}</p>
            <div class="flex flex-col md:flex-row mt-1 mb-2">
              <div v-if="profile.website" class="flex flex-row mr-4">
                <i
                  class="fas fa-link text-dark align-text-bottom pt-1 mr-2"
                ></i>
                <a
                  :href="profile.website"
                  target="_blank"
                  class="text-dark"
                >
                  {{ profile.website.replace(/^https?:\/\//, '') }}
                </a>
              </div>
              <div v-if="joinedDate(profile.created_at)" class="flex flex-row mr-4">
                <i
                  class="far fa-calendar-alt text-dark align-text-bottom pt-1 mr-2"
                ></i>
                <p class="text-dark">Joined {{ joinedDate(profile.created_at) }}</p>
              </div>
            </div>
            <div v-if="!noUser && !loading" class="flex flex-row mt-1">
              <button
                @click="goToFollowing()"
                class="mr-4 flex flex-row hover:underline"
              >
                <span class="font-bold">{{ profile.followings_count || followings.length }}</span>
                <span class="text-dark whitespace-pre"> Following</span>
              </button>
              <button
                @click="goToFollowers()"
                class="flex flex-row hover:underline"
              >
                <span class="font-bold">{{ profile.followers_count || followers.length }}</span>
                <span class="text-dark whitespace-pre"> Followers</span>
              </button>
            </div>
          </div>
          <div v-if="noUser" class="px-5">
            <p class="text-black text-lg">
              @{{ $route.params.id }}
            </p>
          </div>
          <div
            v-if="!noUser && !loading"
            class="flex flex-row justify-evenly mt-2"
          >
            <button
              type="button"
              @click="selectTab('tweets')"
              class="flex-grow text-dark font-bold border-b-2 p-1 md:px-2 md:py-4 hover:bg-lightblue"
              :class="activeTab === 'tweets' ? 'border-blue' : ''"
            >
              Tweets
            </button>
            <button
              type="button"
              disabled
              title="Coming soon"
              aria-label="Tweets & replies (coming soon)"
              class="cursor-not-allowed opacity-50 flex-grow text-dark font-bold border-b-2 p-1 md:px-2 md:py-4"
            >
              Tweets & replies
            </button>
            <button
              type="button"
              disabled
              title="Coming soon"
              aria-label="Media (coming soon)"
              class="cursor-not-allowed opacity-50 flex-grow text-dark font-bold border-b-2 p-1 md:px-2 md:py-4"
            >
              Media
            </button>
            <button
              v-if="isSelf"
              type="button"
              @click="selectTab('likes')"
              class="flex-grow text-dark font-bold border-b-2 p-1 md:px-2 md:py-4 hover:bg-lightblue"
              :class="activeTab === 'likes' ? 'border-blue' : ''"
            >
              Likes
            </button>
            <button
              v-else
              type="button"
              disabled
              title="Only your own likes are visible"
              aria-label="Likes (own profile only)"
              class="cursor-not-allowed opacity-50 flex-grow text-dark font-bold border-b-2 p-1 md:px-2 md:py-4"
            >
              Likes
            </button>
          </div>
        </div>

        <!-- tweets -->
        <template v-if="activeTab === 'tweets'">
          <Loader :loading="loading" />
          <div
            v-if="!noUser && !loading && tweets.length === 0"
            class="flex flex-col items-center justify-center w-full pt-10"
          >
            <p class="font-bold text-lg">
              <span>{{ isSelf ? "You haven't" : `${profile.username || "User"} hasn't` }}</span>
              tweeted yet
            </p>
            <p class="text-sm text-dark">
              When
              <span>{{ isSelf ? "you post" : `${profile.username || "user"} posts` }}</span>
              a tweet, it'll show up here.
            </p>
            <button
              v-if="isSelf"
              @click="tweetNow()"
              class="text-white bg-blue rounded-full font-semibold mt-4 px-4 py-2 hover:bg-darkblue"
            >
              <p class="hidden lg:block">Tweet now</p>
              <i class="fas fa-plus lg:hidden"></i>
            </button>
          </div>
          <div
            v-if="isBlocked"
            class="mx-5 my-4 p-4 border border-lighter rounded bg-lightest text-sm text-dark"
          >
            <p class="font-bold">You blocked @{{ profile.id }}.</p>
            <p class="mt-1">Their tweets are hidden. Use the menu above to unblock if you change your mind.</p>
          </div>
          <Tweets v-if="!noUser && !isBlocked" :tweets="sortedTweets" />
        </template>

        <!-- likes -->
        <template v-else-if="activeTab === 'likes'">
          <Loader :loading="likesLoading" />
          <div
            v-if="!likesLoading && likes.length === 0"
            class="flex flex-col items-center justify-center w-full pt-10 px-5"
          >
            <p class="font-bold text-lg">Nothing liked yet</p>
            <p class="text-sm text-dark text-center">
              Tweets you like will show up here so you can always find your way back to them.
            </p>
          </div>
          <Tweets :tweets="likedTweets" />
        </template>
      </div>
      <DefaultRightBar
          :profile="profile"
      />

      <SetUpProfileOverlay
        v-if="showSetUpProfileModal"
        :showSetUpProfileModal="showSetUpProfileModal"
        @close="showSetUpProfileModal = false"
      />

      <EditProfileOverlay
        v-if="showEditProfileModal"
        :showEditProfileModal="showEditProfileModal"
        @close="onEditProfileClosed"
      />

      <ConfirmDialog
        :show="showBlockConfirm"
        :title="isBlocked ? 'Unblock user' : 'Block user'"
        :message="isBlocked
          ? `Unblock @${profile?.id || ''}? They'll be able to follow you and see your tweets again.`
          : `Block @${profile?.id || ''}? They'll no longer be able to follow you or see your tweets.`"
        :confirm-label="isBlocked ? 'Unblock' : 'Block'"
        :destructive="!isBlocked"
        @cancel="showBlockConfirm = false"
        @confirm="onBlockConfirmed"
      />
  </div>
</template>

<script>
import moment from "moment";
import {defineAsyncComponent} from "vue";
import {warpnetService} from "@/service/service";
import {toast} from "@/lib/toast";

export default {
  name: "Profile",
  components: {
    SideNav: defineAsyncComponent(() => import('@/components/SideNav.vue')),
    DefaultRightBar: defineAsyncComponent(() => import('@/components/DefaultRightBar.vue')),
    SearchBar: defineAsyncComponent(() => import('@/components/SearchBar.vue')),
    Loader: defineAsyncComponent(() => import('@/components/Loader.vue')),
    EditProfileOverlay: defineAsyncComponent(() => import('@/components/EditProfileOverlay.vue')),
    SetUpProfileOverlay: defineAsyncComponent(() => import('@/components/SetUpProfileOverlay.vue')),
    Tweets: defineAsyncComponent(() => import('@/components/Tweets.vue')),
    ConfirmDialog: defineAsyncComponent(() => import('@/components/ConfirmDialog.vue')),
    ReportDialog: defineAsyncComponent(() => import('@/components/ReportDialog.vue')),
  },
  data() {
    return {
      showSetUpProfileModal: false,
      showEditProfileModal: false,
      isSelf: false,
      followingLabel: "Following",
      followPending: false,
      loading: true,
      noUser: false,
      ownerProfile: {},
      profile: {},
      tweets: [],
      users: [],
      followers: [],
      followings: [],
      followingStatus: new Map(),
      followerStatus: new Map(),
      profileMenuOpen: false,
      isBlocked: false,
      isMuted: false,
      showBlockConfirm: false,
      showReportDialog: false,
      showNetworkWarning: true,
      activeTab: 'tweets',
      likes: [],
      likesLoading: false,
      likesLoaded: false,
    };
  },
  computed: {
    sortedTweets() {
      // Render pinned tweets at the top of the user's timeline.
      const pinned = this.tweets.filter(t => t && t.pinned);
      const rest = this.tweets.filter(t => !(t && t.pinned));
      return pinned.concat(rest);
    },
    // isBusiness drives the "Business" badge — the role rides on the user
    // record (domain.User.Role), stamped from the node's NodeInfo, same as any
    // other profile field.
    isBusiness() {
      return this.profile && this.profile.role === "business";
    },
    likedTweets() {
      return this.likes.map(l => l.tweet);
    },
  },
  methods: {
    isMySelf(profileId) {
      return profileId === this.ownerProfile.user_id;
    },
    joinedDate(createdAt) {
      // Guard against a missing/invalid timestamp — moment(undefined) would
      // otherwise return "now" and every profile would read "Joined <today>".
      if (!createdAt) return "";
      const m = moment(createdAt);
      return m.isValid() ? m.format("MMMM YYYY") : "";
    },
    tweetNow() {
      this.$router.push({ name: "Home", query: { compose: 1 } });
    },
    gotoHome() {
      this.$router.push({
        name: "Home",
      });
    },
    async sendMessage() {
      const owner = warpnetService.getOwnerProfile();
      if (!owner?.user_id || !this.profile?.id) return;
      try {
        // Open (creating if needed) the DM with this user, then route to it.
        // The Messages route is namespaced under the owner's id and requires
        // the chat id — pushing without it throws "Missing required param".
        const chat = await warpnetService.createChat(this.profile.id);
        if (!chat || !chat.id) {
          console.error(`sendMessage: could not open chat with ${this.profile.id}`);
          return;
        }
        this.$router.push({
          name: "Messages",
          params: {
            id: owner.user_id,
            chatId: chat.id,
          },
        });
      } catch (err) {
        console.error(`sendMessage failed for ${this.profile.id}:`, err);
        toast.error(err?.message || "Couldn't open a chat with this user.");
      }
    },
    isFollower() {
      return this.followerStatus.get(this.profile.id) || false
    },
    isFollowing() {
      return this.followingStatus.get(this.profile.id) || false
    },
    goToFollowing() {
      this.$router.push({
        name: "Following",
        params: {
          id: this.profile.id,
        },
      });
    },
    goToFollowers() {
      this.$router.push({
        name: "Followers",
        params: {
          id: this.profile.id,
        },
      });
    },
    setUpProfile() {
      this.showSetUpProfileModal = true;
    },
    editProfile() {
      this.showEditProfileModal = true;
    },
    async onEditProfileClosed() {
      this.showEditProfileModal = false;
      const profileId = this.$route.params.id;
      const previousProfile = this.profile;
      try {
        const profile = await warpnetService.getProfile(profileId);
        profile.background_image = await warpnetService.getImage(
            {userId: profileId, key: profile.background_image_key},
        );
        profile.avatar = await warpnetService.getImage(
            {userId: profileId, key: profile.avatar_key},
        );
        this.profile = profile;
      } catch (err) {
        this.profile = previousProfile;
        console.error(`failed to refresh profile [${profileId}] after edit`, err);
      }
    },
    async follow() {
      if (this.followPending) return;
      this.followPending = true;
      this.followingStatus.set(this.profile.id, true); // optimistic
      try {
        await warpnetService.followUser(this.profile.id);
      } catch (err) {
        console.error(`failed to follow [${this.profile.id}]`, err);
        this.followingStatus.set(this.profile.id, false); // rollback
        toast.error(err?.message || "Couldn't follow this user. Please try again.");
      } finally {
        this.followPending = false;
      }
    },
    async unfollow() {
      if (this.followPending) return;
      this.followPending = true;
      this.followingStatus.set(this.profile.id, false); // optimistic
      try {
        await warpnetService.unfollowUser(this.profile.id);
      } catch (err) {
        console.error(`failed to unfollow [${this.profile.id}]`, err);
        this.followingStatus.set(this.profile.id, true); // rollback
        toast.error(err?.message || "Couldn't unfollow this user. Please try again.");
      } finally {
        this.followPending = false;
      }
    },
    async toggleMuteFromProfile() {
      this.profileMenuOpen = false;
      const target = this.profile?.id;
      if (!target) return;
      try {
        if (this.isMuted) {
          await warpnetService.unmuteUser(target);
          this.isMuted = false;
        } else {
          await warpnetService.muteUser(target);
          this.isMuted = true;
        }
      } catch (err) {
        console.error(`failed to toggle mute on [${target}]`, err);
        toast.error(err?.message || "Couldn't update mute. Please try again.");
      }
    },
    openReport() {
      this.profileMenuOpen = false;
      this.showReportDialog = true;
    },
    async submitReport(reason) {
      // type 0 = user profile in ModerationObjectType. One report
      // covers the whole profile surface (username + bio + website +
      // metadata); the moderator picks it up and re-fetches the user
      // directly so it can't be tricked by a malicious reporter.
      try {
        await warpnetService.report({
          type: 0,
          objectId: '',
          targetUserId: this.profile.id,
          targetNodeId: this.profile.node_id || '',
          reason,
        });
        toast.success("Report sent to moderators.");
      } catch (err) {
        console.error(`failed to report [${this.profile.id}]`, err);
        toast.error(err?.message || "Couldn't send the report. Please try again.");
      } finally {
        this.showReportDialog = false;
      }
    },
    // askBlockToggle opens the ConfirmDialog with text that depends on
    // the current block state; onBlockConfirmed performs the actual
    // block / unblock and refreshes local UI so the user can't keep
    // pressing the menu item indefinitely.
    askBlockToggle() {
      this.profileMenuOpen = false;
      this.showBlockConfirm = true;
    },
    async onBlockConfirmed() {
      this.showBlockConfirm = false;
      const target = this.profile?.id;
      if (!target) return;
      try {
        if (this.isBlocked) {
          await warpnetService.unblockUser(target);
          this.isBlocked = false;
          // Reload the profile so its tweets reappear.
          await this.loadProfileBlockState();
        } else {
          await warpnetService.blockUser(target);
          this.isBlocked = true;
          // Hide the (now blocked) user's tweets immediately so the
          // page reflects the block without a manual refresh.
          this.tweets = [];
        }
      } catch (err) {
        console.error(`failed to toggle block on [${target}]`, err);
        toast.error(err?.message || "Couldn't update block. Please try again.");
      }
    },
    async loadProfileBlockState() {
      const target = this.profile?.id;
      if (!target) return;
      try {
        this.isBlocked = await warpnetService.isUserBlocked(target);
      } catch (err) {
        console.warn(`failed to read block state for [${target}]:`, err);
        this.isBlocked = false;
      }
      try {
        this.isMuted = await warpnetService.isUserMuted(target);
      } catch (err) {
        console.warn(`failed to read mute state for [${target}]:`, err);
        this.isMuted = false;
      }
    },
    async loadMore() {
      if (this.activeTab === 'likes') {
        if (this.likesLoading) return;
        const resp = await warpnetService.getLikes(false);
        const items = (resp?.items || []).filter(l => l.tweet && l.tweet.id);
        this.likes = this.likes.concat(items);
        return;
      }
      const tweets = await warpnetService.getTweets({userId:this.profile.id, cursorReset:false});
      this.tweets = this.tweets.concat(tweets);
    },
    async selectTab(tab) {
      this.activeTab = tab;
      if (tab !== 'likes' || this.likesLoaded) return;
      this.likesLoading = true;
      try {
        const resp = await warpnetService.getLikes(true);
        this.likes = (resp?.items || []).filter(l => l.tweet && l.tweet.id);
        this.likesLoaded = true;
      } catch (err) {
        console.error('Failed to load likes:', err);
      } finally {
        this.likesLoading = false;
      }
    },
    closeProfileMenu() {
      this.profileMenuOpen = false;
    },
    enableMastodonMode() {
      const html = document.documentElement;
      html.classList.add("mastodon");
      localStorage.setItem("theme", "mastodon");
    },
    disableMastodonMode() {
      const html = document.documentElement;
      if (html.classList.contains("mastodon")) {
        html.classList.remove("mastodon");
        localStorage.setItem("theme", "light");
      }
    }
  },
  watch: {
    profileMenuOpen(open) {
      if (open) {
        this._menuOutsideHandler = () => this.closeProfileMenu();
        setTimeout(() => {
          if (this._menuOutsideHandler) document.addEventListener("click", this._menuOutsideHandler);
        }, 0);
      } else if (this._menuOutsideHandler) {
        document.removeEventListener("click", this._menuOutsideHandler);
        this._menuOutsideHandler = null;
      }
    },
  },
  beforeUnmount() {
    if (this._menuOutsideHandler) {
      document.removeEventListener("click", this._menuOutsideHandler);
      this._menuOutsideHandler = null;
    }
  },
  async created() {
    console.log("loading component:", this.$options.name);
    try {
      this.loading = true;
      const profileId = this.$route.params.id;
      if (!profileId) {
        this.noUser = true;
        this.loading = false;
        return;
      }

      this.ownerProfile = warpnetService.getOwnerProfile();

      this.profile = await warpnetService.getProfile(profileId);
      if (!this.profile) {
        this.noUser = true;
        this.loading = false;
        return;
      }
      if (this.profile.network && this.profile.network === "mastodon") {
        this.enableMastodonMode()
      } else {
        this.disableMastodonMode();
      }
      this.loading = false;

      this.profile.background_image = await warpnetService.getImage(
          {userId:profileId, key:this.profile.background_image_key},
      );
      this.profile.avatar = await warpnetService.getImage(
          {userId:profileId, key:this.profile.avatar_key},
      )

      this.isSelf = this.isMySelf(profileId);

      if (!this.isSelf) {
        await this.loadProfileBlockState();
      }

      [this.users, this.tweets, this.followers, this.followings] = await Promise.all([
        warpnetService.getUsers({profileId:profileId, cursorReset:true}),
        warpnetService.getTweets({userId:profileId, cursorReset:true}),
        warpnetService.getFollowers({userId:profileId, cursorReset: true}),
        warpnetService.getFollowings({userId:profileId, cursorReset: true})
      ]);
    } catch (err) {
      console.error('Failed to load profile:', err);
      this.noUser = true;
      this.loading = false
      return
    }
    for (const p of this.users) {
      const followingStatus = await warpnetService.isFollowing(p.id);
      this.followingStatus.set(p.id, followingStatus);

      const followerStatus = await warpnetService.isFollower(p.id);
      this.followerStatus.set(p.id, followerStatus);
    }

    // The viewed profile is not necessarily part of this.users (that list
    // holds related/suggested users), so resolve its own follow state
    // explicitly — otherwise the header button always renders "Follow"
    // even when the owner already follows this user. Self profiles show
    // "Edit profile" instead of the follow button, so skip them.
    if (!this.isSelf && this.profile?.id) {
      const [selfFollowing, selfFollower] = await Promise.all([
        warpnetService.isFollowing(this.profile.id),
        warpnetService.isFollower(this.profile.id),
      ]);
      this.followingStatus.set(this.profile.id, selfFollowing);
      this.followerStatus.set(this.profile.id, selfFollower);
    }
  },
};
</script>
